"""Pricing calculations for orders."""
from typing import List, Optional, Tuple
from models import OrderItem, Customer, TAX_RATES, SHIPPING_RATES, FREE_SHIPPING_THRESHOLD, DISCOUNT_TIERS


def calculate_subtotal(items: List[OrderItem]) -> float:
    return round(sum(item.line_total for item in items), 2)


def apply_discount(subtotal: float, customer_tier: str, discount_code: Optional[str] = None) -> Tuple[float, float]:
    tier_rate = DISCOUNT_TIERS.get(customer_tier, 0.0)
    after_tier = round(subtotal * (1 - tier_rate), 2)

    code_discount = 0.0
    if discount_code == "SAVE10":
        code_discount = min(10.0, after_tier)
    elif discount_code == "HALF":
        code_discount = round(after_tier * 0.5, 2)

    final = round(after_tier - code_discount, 2)
    total_discount = round(subtotal - final, 2)
    return max(final, 0.0), total_discount


def calculate_tax(amount: float, region: str) -> float:
    rate = TAX_RATES.get(region, TAX_RATES["default"])
    return round(amount * rate, 2)


def calculate_shipping(method: str, subtotal: float) -> float:
    if method == "standard" and subtotal >= FREE_SHIPPING_THRESHOLD:
        return 0.0
    return SHIPPING_RATES.get(method, SHIPPING_RATES["standard"])


def calculate_total(items: List[OrderItem], customer: Customer, 
                    shipping_method: str = "standard",
                    discount_code: Optional[str] = None) -> dict:
    subtotal = calculate_subtotal(items)
    discounted, discount_value = apply_discount(subtotal, customer.tier, discount_code)
    tax = calculate_tax(discounted, customer.region)
    shipping = calculate_shipping(shipping_method, subtotal)
    total = round(discounted + tax + shipping, 2)

    return {
        "subtotal": subtotal,
        "discount": discount_value,
        "after_discount": discounted,
        "tax": tax,
        "shipping": shipping,
        "total": total,
    }

