"""Order processing operations."""
from typing import Dict, List, Optional, Tuple
from datetime import datetime
from models import Customer, Order, OrderItem, ORDER_STATUSES, SHIPPING_RATES
from pricing import calculate_total


_orders: Dict[int, Order] = {}
_next_id: int = 1


def _reset_store():
    global _orders, _next_id
    _orders = {}
    _next_id = 1


def create_order(customer: Customer, items: List[OrderItem],
                 shipping_method: str = "standard",
                 discount_code: Optional[str] = None,
                 notes: str = "") -> Tuple[dict, int]:
    global _next_id

    errors = []
    if not items:
        errors.append("Order must have at least one item")
    if not customer.name:
        errors.append("Customer name is required")
    if not customer.email:
        errors.append("Customer email is required")
    if shipping_method not in SHIPPING_RATES:
        errors.append(f"Invalid shipping method: {shipping_method}")
    for item in items:
        if item.quantity < 1:
            errors.append(f"Invalid quantity for {item.product_name}")
        if item.unit_price <= 0:
            errors.append(f"Invalid price for {item.product_name}")

    if errors:
        return {"errors": errors}, 400

    now = datetime.now().isoformat()
    order = Order(
        id=_next_id,
        customer=customer,
        items=items,
        shipping_method=shipping_method,
        discount_code=discount_code,
        notes=notes,
        created_at=now,
        updated_at=now,
    )
    _next_id += 1
    _orders[order.id] = order

    pricing = calculate_total(items, customer, shipping_method, discount_code)
    result = order.to_dict()
    result["pricing"] = pricing
    return result, 201


def update_order(order_id: int, **kwargs) -> Tuple[dict, int]:
    if order_id not in _orders:
        return {"error": "Order not found"}, 404

    order = _orders[order_id]

    if order.status in ("cancelled", "refunded"):
        return {"error": f"Cannot update {order.status} order"}, 400

    allowed_fields = {"notes", "shipping_method", "status"}
    errors = []

    for key, value in kwargs.items():
        if key not in allowed_fields:
            errors.append(f"Cannot update field: {key}")
        elif key == "shipping_method" and value not in SHIPPING_RATES:
            errors.append(f"Invalid shipping method: {value}")
        elif key == "status" and value not in ORDER_STATUSES:
            errors.append(f"Invalid status: {value}")

    if errors:
        return {"errors": errors}, 400

    for key, value in kwargs.items():
        if key in allowed_fields:
            setattr(order, key, value)

    order.updated_at = datetime.now().isoformat()

    pricing = calculate_total(order.items, order.customer, 
                              order.shipping_method, order.discount_code)
    result = order.to_dict()
    result["pricing"] = pricing
    return result, 200


def cancel_order(order_id: int) -> Tuple[dict, int]:
    if order_id not in _orders:
        return {"error": "Order not found"}, 404

    order = _orders[order_id]

    if order.status in ("shipped", "delivered"):
        return {"error": f"Cannot cancel {order.status} order"}, 400

    if order.status == "cancelled":
        return {"error": "Order is already cancelled"}, 400

    order.status = "cancelled"
    order.updated_at = datetime.now().isoformat()
    return {"message": "Order cancelled", "order": order.to_dict()}, 200


def refund_order(order_id: int) -> Tuple[dict, int]:
    if order_id not in _orders:
        return {"error": "Order not found"}, 404

    order = _orders[order_id]

    if order.status != "delivered":
        return {"error": f"Can only refund delivered orders, current status: {order.status}"}, 400

    order.status = "refunded"
    order.updated_at = datetime.now().isoformat()

    pricing = calculate_total(order.items, order.customer,
                              order.shipping_method, order.discount_code)
    return {
        "message": "Order refunded",
        "refund_amount": pricing["total"],
        "order": order.to_dict(),
    }, 200


def get_order_summary(order_id: int) -> Tuple[dict, int]:
    if order_id not in _orders:
        return {"error": "Order not found"}, 404

    order = _orders[order_id]
    pricing = calculate_total(order.items, order.customer,
                              order.shipping_method, order.discount_code)
    result = order.to_dict()
    result["pricing"] = pricing
    return result, 200
